+
+fn permissive_policy() -> ExtensionPolicy {
+    ExtensionPolicy {
+        mode: ExtensionPolicyMode::Permissive,
+        max_memory_mb: 256,
+        default_caps: Vec::new(),
+        deny_caps: Vec::new(),
+        ..Default::default()
+    }
+}
+
+fn scenario_id(call_id: &str) -> &'static str {
+    if call_id.starts_with("benign-") {
+        "benign"
+    } else if call_id.starts_with("adversarial-") {
+        "adversarial"
+    } else {
+        "recovery"
+    }
+}
+
